noncompliant:
for (int i = 0; i < 0; i++) // Noncompliant: condition is false from the start, loop never executes
{
    Console.WriteLine(i);
}

for (int i = 10; i < 5; i++) // Noncompliant: condition is false from the start
{
    Console.WriteLine(i);
}

compliant:
for (int i = 0; i < 10; i++) // Compliant: condition is true at least once
{
    Console.WriteLine(i);
}

if (maxValue > 0) // Compliant: check condition before loop
{
    for (int i = 0; i < maxValue; i++)
    {
        Console.WriteLine(i);
    }
}
